import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
print('=== Comparison ===')
changes = False
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key, 'MISSING')
    av = a.get(key, 'MISSING')
    status = '✓ unchanged' if bv == av else f'CHANGED {bv} -> {av}'
    if bv != av: changes = True
    print(f'  {key[0]:15s} {key[1]:55s} {bv:10s} -> {av:10s}  {status}')
if not changes: print('\\nAll packages resolve identically. Conversion is version-neutral.')
"", "description": "Compare baseline vs post-conversion", "initial_wait": 30}

